-- Enrichment marathon batch: Lu.ma, Luanti, LubeLogger, Lucky Orange, Luma AI, Luma Health, Lumar, Lunacy

-- ── Lu.ma ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Lu.ma (Luma) is an events and ticketing platform for creating, promoting, and managing online and in-person events, meetups, and communities.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Plus plan from $59/month)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Estimated 51-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Lu.ma Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Lu.ma (Luma) review 2026 covering event ticketing and community features, Free vs Plus pricing, pros, cons, and top alternatives for event organizers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Lu.ma, commonly written and referred to as Luma, is an events and community platform founded in 2020 by Victor Pontis alongside a small founding engineering team, initially operating out of New York City. The product began as a lightweight way to create polished event pages with RSVP and calendar tools, and grew during the pandemic-era boom in virtual events before pivoting toward hybrid and in-person gatherings as restrictions lifted. Luma raised a 3 million dollar seed round in December 2020 led by investors including Maven Ventures and Venrock, and in 2024 closed a 12 million dollar Series A that funded expansion to roughly 50 employees, the opening of a San Francisco hub, and the build-out of enterprise CRM integrations. By early 2026 the platform reportedly powers more than 1.5 million events annually and has become deeply embedded in the technology, venture capital, and artificial intelligence conference circuits, hosting recurring communities such as The AI Collective and large-scale programs like the AI+ Renaissance conference series. It is important to distinguish Lu.ma from two other companies that share the Luma name: Luma AI (lumalabs.ai), a generative AI video and 3D company behind Dream Machine, and Luma Health, a healthcare patient engagement platform. All three are unrelated businesses that happen to use similar branding. Architecturally, Lu.ma is a web-based SaaS product centered on an event page builder, a public and private calendar system for organizing recurring communities, guest management with waitlists and approval flows, integrated payments and ticketing, check-in tools via a companion mobile app, and native Zoom integration for hybrid or virtual sessions. Hosts can customize registration questions, send email and push reminders to guests, and issue tickets with QR codes for door scanning. The calendar feature differentiates Luma from transaction-first competitors such as Eventbrite by letting organizers build a persistent, followable community hub rather than a one-off event listing, which is a major reason it has become popular with recurring meetup series, hackathons, and demo nights. Pricing follows a freemium model. The free tier supports unlimited events and guests, up to 500 weekly invite sends, guest check-in, and payment processing with a 5 percent platform fee on paid tickets, along with up to three calendar admins. The Plus plan is 59 dollars per month billed annually and removes the platform fee, raises the weekly invite allowance to 5,000 sends, adds tax collection, custom event URLs, five calendar admins, API access, and priority support; additional weekly send capacity can be purchased in tiers up to 100,000 sends per week. An Enterprise tier offers custom pricing for organizations that need single sign-on, advanced integrations, and additional security controls. Luma's target audience spans independent event organizers, community builders, startup and venture capital teams running recurring meetups, conference producers, and creators monetizing workshops or webinars. Its closest competitors include Eventbrite, which remains the dominant player for large-scale ticketed events, Meetup, which focuses on recurring interest-based groups, and newer social-first tools like Partiful that target casual social gatherings rather than professional or community events. Luma differentiates itself through design quality, a calendar-first community model, tight integration with the Zoom and payments ecosystem, and outsized organic adoption within the tech and AI startup world, which has made it something of a default choice for demo days, hackathons, and investor-adjacent gatherings.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c973c5c5-70a6-48ab-b061-1028ca2b9440';

