-- ── Luanti ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Luanti is a free, open-source voxel game engine and sandbox platform, formerly known as Minetest, renamed in October 2024.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Volunteer open-source community (no fixed headcount)$q$, company_size),
  headquarters = COALESCE($q$Distributed / open-source project (no fixed headquarters)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Multiple community-translated languages$q$]::text[],
  seo_title = COALESCE($q$Luanti Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Luanti (formerly Minetest) review 2026: open-source voxel engine features, modding with Lua, pricing, pros, cons, and alternatives like Minecraft.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Luanti is a free and open-source voxel game creation engine that was originally released in October 2010 as Minetest, created by Finnish developer Perttu Ahola as an exploration of the block-building mechanics popularized by Minecraft. Over more than a decade of community-driven development, the project evolved from a single Minecraft-like game into a general-purpose engine capable of powering many distinct voxel games and mods, which made the original name increasingly inaccurate and, according to the project team, a source of confusion and mild embarrassment because of the word test in the name. On October 13, 2024, the project was officially renamed to Luanti, a name that combines Lua, the scripting language the engine is built around, with the Finnish word luonti, meaning creation. The rename was the result of years of community brainstorming and was intended to signal that the software is a general engine for building voxel games rather than a single Minecraft clone; the original Minetest game itself continues to exist as the default bundled game within the Luanti engine. Luanti is maintained by a volunteer community referred to as the Luanti Team, with development happening in the open on GitHub under the organization luanti-org, and it has no traditional company structure, headquarters, or commercial funding rounds; it is sustained through open-source contributions and voluntary donations. The engine's source code is released under the MIT license, allowing free commercial and non-commercial use, modification, and redistribution, while game content and media assets are generally distributed under Creative Commons licenses such as CC BY-SA 3.0, and iconography from Font Awesome is used under CC BY 4.0. Technically, Luanti provides an enormous playable world of up to 62,000 by 62,000 by 62,000 blocks, with mining and building extending roughly 31,000 blocks in each vertical direction, and it supports single-player, local multiplayer, and dedicated online server play. Its defining feature is a comprehensive Lua application programming interface that lets creators write custom games, mods, and map generators without touching the engine's C++ core, and the ContentDB repository hosts more than 3,000 community-created mods, games, and texture packs that can be installed directly from within the client. Luanti runs natively on Windows, macOS, GNU/Linux, BSD variants, and Android, making it broadly cross-platform and lightweight enough to run on modest hardware, which distinguishes it from proprietary voxel games that require more powerful systems or subscription-based server hosting. Because it costs nothing to download, modify, or self-host, Luanti's primary audience includes hobbyist game developers learning Lua scripting, educators using voxel worlds for teaching programming concepts, retro and open-source gaming communities, and players seeking a Minecraft-like experience without licensing costs or proprietary restrictions. Its closest comparison point is Minecraft, from which it draws its core gameplay inspiration, but Luanti differentiates itself by being fully open source, free of any purchase price or subscription, and architected from the ground up as a moddable engine rather than a single fixed game, giving developers far more latitude to build entirely custom voxel experiences. Other comparison points include other open-source or community-driven sandbox projects, though Luanti has one of the longest continuous development histories and largest mod ecosystems in that space, with releases continuing on a regular cadence, including version 5.16.1 in 2026.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '77a26385-9077-48ad-bcca-92dcc22cef2e';

