-- ── LubeLogger ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$LubeLogger is a free, open-source, self-hosted web app for tracking vehicle maintenance, service records, and fuel mileage.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$Small independent developer / open-source contributor team$q$, company_size),
  headquarters = COALESCE($q$Price, Utah, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$LubeLogger Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LubeLogger review 2026: self-hosted open-source vehicle maintenance tracker features, setup, pricing, pros, cons, and alternatives compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LubeLogger is a free and open-source, self-hosted vehicle maintenance and fuel mileage tracking application developed by Hargata Softworks, a small software outfit based in Price, Utah, and published under the developer handle hargata on GitHub. The project, hosted in the hargata/lubelog repository, gained visibility in the self-hosting and home-lab community in early 2024 after being highlighted on Hacker News and community forums like Lemmy for its combination of thorough functionality and its unconventional name, which plays on the automotive term lube job alongside the familiar logger suffix used by many self-hosted tracking tools. As an open-source project, LubeLogger is licensed under the MIT license, permitting free personal and commercial use, modification, and redistribution, and it has no venture funding, company headcount, or paid corporate structure in the traditional sense; it is sustained through community contributions, GitHub stars, which number in the thousands, and voluntary support. LubeLogger is distributed primarily as a Docker container image, published to the GitHub Container Registry, and also as a Windows standalone executable, making it straightforward to deploy on home servers, NAS devices, or self-hosting platforms such as Umbrel. The core architecture is a web application with a backend API, meaning users interact with it through a browser after deploying the container on their own infrastructure, which keeps vehicle and maintenance data entirely under the user's control rather than stored on a third-party cloud service. Functionally, LubeLogger provides a dashboard summarizing expenses by year, month, and category; a planner for organizing upcoming maintenance to-do items by type and priority; detailed service record logging with support for attaching receipts and documents; fuel economy tracking that supports multiple units including MPG, UK MPG, liters per 100 kilometers, and kilometers per liter; reminders for scheduled maintenance triggered by either calendar date or odometer mileage; and a supplies tracker for logging consumable inventory like oil or filters tied to specific vehicles. Additional capabilities include generation of professional-looking vehicle service reports suitable for resale documentation, support for multiple user accounts on a single instance, user-customizable fields for adapting the data model to unusual vehicle types, CSV import and export for migrating data in or out of the system, a documented API for integrations, and single sign-on support for users who want to tie authentication into an existing identity provider. LubeLogger's target audience is primarily technically inclined vehicle owners, self-hosting and home-lab enthusiasts, and small fleet or multi-vehicle households who want a private, ad-free alternative to consumer apps like Fuelly, Simply Auto, or CARFAX Car Care, all of which typically store data in a vendor cloud and may carry subscription costs or advertising. Because LubeLogger requires users to run their own server or container, its differentiation is squarely on data ownership, privacy, and zero licensing cost rather than convenience, which appeals to the same audience that gravitates toward other self-hosted tools in categories like home media servers or password managers. The project maintains an active public demo instance at demo.lubelogger.com for prospective users to try the interface before committing to self-hosting, and ongoing development is tracked through frequent GitHub releases that have steadily added features such as reminders, reporting, and API access since the tool's initial public releases.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '270d9194-a92c-41d2-84b2-40be25395e12';

