-- ── Luma AI ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Luma AI is a generative AI company behind Dream Machine, building text-to-video, image, and 3D generation models, unrelated to Lu.ma or Luma Health.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free (Plus plan from $25-30/month)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Over 250 employees$q$, company_size),
  headquarters = COALESCE($q$Palo Alto, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Luma AI Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Luma AI review 2026: Dream Machine, Ray3, Photon, and Genie 3D features, pricing plans, funding, pros, cons, and alternatives compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Luma AI, operating from lumalabs.ai, is a generative artificial intelligence company founded in 2021 by Amit Jain, Alex Yu, and Alberto Taiuti, headquartered in Palo Alto, California. It should not be confused with two other unrelated companies that use similar Luma branding: Lu.ma, an events and ticketing platform at lu.ma, and Luma Health, a healthcare patient engagement company. Luma AI's stated mission is to build multimodal general intelligence models that can generate, understand, and operate within representations of the physical world, and its work spans AI-generated video, images, and 3D assets. The company built an early reputation in neural radiance fields and 3D capture technology before pivoting its primary public focus toward generative video with the June 2024 launch of Dream Machine, a text-to-video and image-to-video web application that quickly attracted a large consumer and creative-professional user base; by early 2026 Dream Machine reportedly had more than 30 million registered users and generated approximately 21.2 million dollars in revenue during 2025. Luma AI has raised more than 1.07 billion dollars in disclosed funding across multiple rounds from investors including Amazon, General Catalyst, NVentures, Amplify Partners, Andreessen Horowitz, and AMD Ventures. Its largest and most recent round was a 900 million dollar Series C announced in November 2025, led by Saudi Arabia's HUMAIN and valuing the company above 4 billion dollars, which also established Project Halo, a planned 2-gigawatt AI supercomputing cluster to be built in Saudi Arabia in partnership with HUMAIN. The company has grown rapidly alongside this funding, with employee counts reported in the low hundreds through 2025 and continuing expansion into new offices in London and Riyadh as of 2026. Luma AI's product suite is organized around several distinct models accessible both through its consumer-facing web apps and its developer API, which launched in September 2024. Dream Machine remains the flagship product for text-to-video, image-to-video, video-to-video, and video extension generation. Ray2 and the newer Ray3, released in September 2025 and marketed as the first reasoning video model capable of generating high-fidelity 16-bit HDR output, represent the underlying video generation architecture and are available at different speed and quality tiers, including a faster and cheaper Ray2 Flash variant. Photon and Photon Flash are Luma's image generation models, built for fast, high-quality image synthesis. Genie is a text-to-3D tool that generates downloadable 3D mesh files in formats including GLB, OBJ, and USDZ in roughly ten seconds, aimed at game developers, 3D artists, and virtual production teams. Consumer pricing is organized into Plus, Pro, and Ultra subscription tiers, priced at approximately 30, 90, and 300 dollars per month respectively when billed monthly, with discounted annual pricing offering up to 20 percent savings; each tier provides an increasing monthly credit allowance, ranging from roughly 10,000 credits on Plus to 150,000 credits on Ultra, along with escalating usage limits for Luma's automated agent tooling. Business-oriented Team and Enterprise plans are available at custom pricing and add team management, shared credit pools, usage analytics, single sign-on, and for Enterprise customers, custom model fine-tuning. API pricing for developers is usage-based, with reported costs of roughly 0.10 dollars per five-second clip for Ray2 Flash, 0.40 dollars for full Ray2, 0.002 dollars per image for Photon Flash, and 0.05 dollars per mesh for Genie. Luma AI's target audience includes independent creators and marketers who use Dream Machine for short-form video content, game and 3D artists using Genie for rapid asset prototyping, and enterprise and developer customers integrating Luma's models via API into larger creative or production pipelines. Its primary competitors in generative video include Runway, OpenAI's Sora, Google's Veo, Pika, and Kling, while in 3D generation it competes with tools like Meshy and Tripo; Luma differentiates itself through its focus on physically grounded, reasoning-capable video generation and its parallel investment in 3D and spatial intelligence rather than video alone.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '35ea48fd-76db-4106-94b4-24dc1d80bfc9';

