-- ── Lumar ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Lumar is an enterprise technical SEO and website intelligence platform, formerly known as DeepCrawl, used to crawl, monitor, and protect large websites.$q$, short_description),
  pricing_model = COALESCE($q$Custom / Quote-based$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Estimated 50-100 employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Lumar Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Lumar (formerly DeepCrawl) review 2026: enterprise SEO crawling and website intelligence features, pricing, pros, cons, and alternatives like Botify.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Lumar is an enterprise technical SEO and website intelligence platform that was originally founded in 2010 in the United Kingdom under the name DeepCrawl. The company built its early reputation as a large-scale website crawler purpose-built for technical SEO teams at enterprise organizations, distinguishing itself from consumer or small-business SEO tools by focusing on the crawling and auditing needs of very large, complex websites with millions of URLs. On September 29, 2022, the company rebranded from DeepCrawl to Lumar, a name the company said was chosen to evoke illumination, reflecting its positioning as a tool that helps organizations see their website's technical foundations clearly in order to uncover new opportunities to drive traffic and conversions. The rebrand accompanied a broader expansion of the product from a narrowly focused technical SEO crawler into what the company describes as a website intelligence platform intended to serve digital marketing and engineering teams more broadly, not just dedicated SEO specialists. Lumar is headquartered in London, England, with additional offices reported in New York and Krakow, Poland; reported employee counts vary meaningfully across data providers, from roughly a dozen up to the low hundreds, likely reflecting differences in how contractors, regional teams, and historical snapshots are counted. Lumar's operating entity is registered as Written Byte Ltd, trading as Lumar, and the company has at various points been associated with ownership or investment from GMO TECH Holdings, a Japan-based, Tokyo Stock Exchange-listed digital marketing group. Product-wise, Lumar is organized around four coordinated applications. Analyze is the core cloud-based crawler, capable of crawling large websites and surfacing more than 350 distinct technical SEO reports covering issues like crawl budget waste, indexability problems, broken links, duplicate content, and site architecture. Monitor provides ongoing, multi-site tracking with trend lines and automated alerts so teams can catch regressions as they happen rather than only during periodic audits. Protect integrates into a customer's CI/CD pipeline to test staging or pre-production builds for SEO regressions before they are deployed to a live site, aiming to prevent costly technical SEO mistakes, like accidental noindex tags or broken canonical URLs, from ever reaching production. Impact rounds out the suite with high-level dashboards and benchmarking data intended for executive stakeholders who need summarized site health and business-impact reporting rather than granular crawl data. Because Lumar targets large enterprise organizations with complex sites, its client base is reported to include major brands such as Adobe, Microsoft, eBay, PayPal, Comcast, and Deloitte, and the platform is generally positioned and priced for organizations with sizable marketing technology budgets rather than freelancers or small businesses. Lumar does not publish pricing publicly; prospective customers must request a custom quote through the company's sales process, with pricing and packaging described by the company as flexible and tailored to the specific combination of Analyze, Monitor, Protect, and Impact modules a customer needs, as well as crawl volume and site count. Lumar's primary competitors in the enterprise technical SEO and site crawling space include Botify, ContentKing (part of Conductor), Screaming Frog for more manual or smaller-scale crawling, and OnCrawl, with Botify generally considered its closest direct rival for large enterprise accounts. Lumar differentiates itself through its long operating history dating back to 2010, its CI/CD-integrated Protect module aimed at preventing SEO regressions before deployment rather than only detecting them afterward, and its broader positioning as a website intelligence platform spanning technical SEO, monitoring, and executive reporting in one coordinated product suite.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '76b116d0-5bc2-4a6a-93eb-906109fc7d61';

