-- ── Lunacy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Lunacy is a free, cross-platform graphic and UI design tool by Icons8 with built-in AI tools and design assets, positioned as an alternative to Figma and Sketch.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$Estimated 50 employees (Icons8, parent company)$q$, company_size),
  headquarters = COALESCE($q$New York, United States (Icons8, parent company)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Lunacy Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Lunacy by Icons8 review 2026: free design tool features, AI tools, pricing plans, pros, cons, and how it compares to Figma and Sketch.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Lunacy is a free graphic and UI design application developed by Icons8, a design-assets company whose broader history traces back to a small team of designers working with clients like Oracle, Motorola, and Europol in the early 2000s before formally incorporating as Icons8 in 2012. Lunacy itself began life in 2016 as a simple Sketch file viewer for Windows, built to solve the problem that Sketch, which had become a default standard design tool, was available exclusively on macOS and left Windows-based designers unable to open or view Sketch files. Early on, Sketch changed its file format shortly after Lunacy's initial release, forcing the team to rewrite much of the underlying code, but the viewer nonetheless became one of the top downloaded design tools in the Microsoft Store. From there, Icons8 progressively built out Lunacy into a full editor, releasing Lunacy 3.0 as a native Windows application capable of opening, editing, and saving true .sketch files, and continuing through subsequent major versions, including Lunacy 5.0, which added an integrated vector editor alongside built-in access to icons, photos, and illustrations, and later versions that expanded to native macOS and Linux clients and introduced AI-powered tools. Icons8, the parent company, is reported to be headquartered in New York with additional distributed team presence, and reported employee counts across various data sources range from roughly 47 to 55 people, making it a small, independently operated company relative to venture-backed design tool competitors like Figma. As a product, Lunacy is a full-featured vector design application supporting artboards, responsive design constraints, interactive prototyping with clickable links between screens, and native compatibility with .sketch files, positioning it as a direct alternative for teams that want Sketch-like or Figma-like workflows without being locked into macOS or a browser-based subscription tool. A defining differentiator is that Lunacy runs as a native desktop application on Windows, macOS, and Linux and can be used entirely offline, in contrast to Figma, which is primarily browser-based and requires an internet connection for most of its functionality. Lunacy also ships with deep integration into Icons8's own asset library, giving users in-app access to more than 1.5 million free icons, photos, illustrations, and mockups directly inside the design canvas, alongside built-in AI tools such as a background remover, an image upscaler, and an AI avatar generator. Pricing follows a freemium structure: the core desktop application and most major design features are free for both personal and commercial use with no feature restrictions on the base editor, while paid add-ons unlock cloud collaboration and asset-related upgrades. A free team plan supports up to three members and ten cloud documents, a personal cloud subscription costs approximately 4.99 dollars per month or 47.99 dollars per year and adds unlimited private cloud documents plus extended file version history and recovery windows, a professional team plan is priced at 4.99 dollars per seat per month with no limits on documents or version history, and a separate asset subscription priced around 9.99 dollars per month or 95.99 dollars per year unlocks unlimited downloads from the Icons8 asset library without attribution requirements plus full access to the AI-powered design tools. Lunacy's target audience includes solo designers, startups, and small teams who want a capable, no-cost design tool, particularly those on Windows or Linux who are otherwise excluded from Sketch's Mac-only ecosystem, as well as users who value offline-first, locally stored design files over cloud-only workflows. Its main competitors are Figma, the dominant browser-based collaborative design tool, Sketch, the Mac-only tool Lunacy originally aimed to complement, Adobe XD, and other emerging free or open-source design tools like Penpot. Lunacy differentiates itself primarily on price, being free with no core feature restrictions, on cross-platform native desktop support including Linux, and on its built-in, no-extra-cost access to a large stock asset library and AI design utilities bundled directly into the editor.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc';

