INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Event pages$q$, $q$Branded, customizable landing pages for each event with cover images, descriptions, and registration forms.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Community calendars$q$, $q$Public or private calendars that let hosts build a followable community rather than a one-off listing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Ticketing and payments$q$, $q$Built-in payment processing for paid events, with configurable fees, discount codes, and tax collection on paid plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Guest check-in app$q$, $q$A companion mobile app for scanning QR-code tickets and managing door check-in in real time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Zoom integration$q$, $q$Native connection to Zoom for hosting virtual or hybrid sessions directly from an event page.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Automated communications$q$, $q$Scheduled email and push reminders to registered guests before and after events.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$API access$q$, $q$Programmatic access to event and guest data for CRM and marketing integrations on Plus and Enterprise plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Multi-admin calendar management$q$, $q$Support for multiple team members to co-manage a calendar and its events.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Polished, fast event page creation with minimal setup$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Calendar model builds a durable community following instead of one-off ticket sales$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Free tier is genuinely usable for unlimited events$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Strong adoption within the tech, startup, and AI event ecosystem$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Simple, well-designed check-in flow via companion app$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$5 percent platform fee on paid tickets unless upgraded to Plus$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Less mature for very large-scale ticketed events compared to Eventbrite$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Enterprise features like SSO require custom, undisclosed pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Limited built-in marketing/promotion tools compared to dedicated event marketing suites$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Weekly invite send limits can require add-on purchases for high-volume communities$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Is Lu.ma free to use?$q$, $q$Yes, Luma offers a free plan with unlimited events and guests, though paid tickets incur a 5 percent platform fee unless the host upgrades to the Plus plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$What is the difference between Lu.ma and Luma AI?$q$, $q$They are unrelated companies. Lu.ma is an events and ticketing platform, while Luma AI, at lumalabs.ai, is a separate company that makes AI video and 3D generation tools such as Dream Machine.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Does Lu.ma support virtual and hybrid events?$q$, $q$Yes, Luma has native Zoom integration so hosts can run virtual or hybrid sessions directly from an event page.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$How much does Lu.ma Plus cost?$q$, $q$Luma Plus costs 59 dollars per month when billed annually, and removes the 5 percent platform ticket fee while adding higher invite limits, tax collection, and API access.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Can I sell tickets on Lu.ma?$q$, $q$Yes, Luma includes built-in payment processing for paid ticketed events on both the Free and Plus plans.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Who uses Lu.ma?$q$, $q$Luma is used by independent event organizers, startup and venture capital teams, conference producers, and community builders, and has become especially popular for recurring tech and AI meetups and hackathons.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Recurring community meetups$q$, $q$Organizers build a followable calendar to host regular meetups, workshops, or demo nights under one branded community hub.$q$, $q$Community organizers and meetup hosts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Startup and conference events$q$, $q$Startups and conference producers use Luma to sell tickets, manage guest lists, and check in attendees for in-person or hybrid events.$q$, $q$Startup teams and conference organizers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Virtual workshops and webinars$q$, $q$Creators run paid or free virtual sessions through Luma's Zoom integration, collecting registrations and automating reminders.$q$, $q$Creators and educators hosting online sessions$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Unlimited events and guests","Up to 500 weekly invites","Guest check-in","Payments with 5 percent platform fee","Up to 3 calendar admins"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Plus$q$, $q$$59/month$q$, $q$Billed annually$q$, NULL, $q$["0 percent platform fee","Up to 5,000 weekly invites","Tax collection","Custom event URLs","5 calendar admins","API access","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Single sign-on","Advanced integrations","Custom features","Additional security controls"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lu.ma is an events and ticketing platform that lets organizers build branded event pages, manage guest lists, sell tickets, and run recurring community calendars. Founded in 2020 and now headquartered in San Francisco, it has grown into one of the most widely used tools for tech, startup, and AI community events.$q$, $q$Unlike transaction-first ticketing sites, Luma emphasizes a persistent calendar that followers can subscribe to, turning a single event into an ongoing community relationship between host and audience.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes customizable event pages, RSVP and waitlist management, integrated payments and ticketing with QR-code check-in, a companion check-in app, native Zoom integration for virtual and hybrid sessions, and shareable public or private calendars for recurring communities.$q$, $q$Hosts can collect custom registration questions, send automated email and push reminders, issue discount codes, and, on paid plans, connect the platform via API to internal CRM and marketing tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c973c5c5-70a6-48ab-b061-1028ca2b9440', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Luma's Free plan supports unlimited events and guests with a 5 percent fee on paid ticket sales. The Plus plan, at 59 dollars per month billed annually, removes that fee and unlocks higher invite volumes, custom URLs, tax collection, and API access.$q$, $q$Larger organizations can move to a custom-priced Enterprise tier with single sign-on and advanced security and integration options.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Lua modding API$q$, $q$A comprehensive scripting interface for building custom games, mods, and mechanics without modifying the engine's C++ core.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Massive voxel worlds$q$, $q$Playable maps up to 62,000 by 62,000 by 62,000 blocks with deep vertical mining and building space.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$ContentDB mod repository$q$, $q$An in-client repository with over 3,000 community-made mods, games, and texture packs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Cross-platform support$q$, $q$Native builds for Windows, macOS, GNU/Linux, BSD, and Android.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Multiplayer and dedicated servers$q$, $q$Support for local co-op play and self-hosted or community dedicated servers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Custom map generation$q$, $q$Configurable and moddable world generators for building unique terrain types and biomes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Open licensing$q$, $q$MIT-licensed engine code with CC-licensed game assets, permitting free commercial and non-commercial use.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Active volunteer development$q$, $q$Regular releases maintained by the Luanti Team and open-source contributors on GitHub.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Completely free and open source with no purchase price$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Extremely deep modding and customization via Lua$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Large, active library of community mods and games via ContentDB$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Runs on modest hardware across five major platforms including Android$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$No corporate ownership, subscription, or licensing restrictions$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Visuals and polish generally lag behind commercial titles like Minecraft$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$No official company support channel, only community and volunteer maintainers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Rebrand from Minetest to Luanti in 2024 can still cause naming confusion$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Mod quality and documentation vary widely across ContentDB$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Steeper learning curve for building custom games compared to using the engine to just play$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Is Luanti the same as Minetest?$q$, $q$Yes, Luanti is the new name for Minetest. The project was renamed on October 13, 2024, combining Lua, its scripting language, with the Finnish word for creation, luonti.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Is Luanti free to use?$q$, $q$Yes, Luanti is completely free, open-source software licensed under MIT for its code and Creative Commons licenses for most game content.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Can I create my own games with Luanti?$q$, $q$Yes, Luanti exposes a full Lua API that lets developers build entirely custom games, mods, and map generators on top of the engine.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$What platforms does Luanti support?$q$, $q$Luanti runs natively on Windows, macOS, GNU/Linux, BSD systems, and Android.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Is Luanti similar to Minecraft?$q$, $q$Luanti draws inspiration from Minecraft's voxel building and mining mechanics but is a fully open-source, moddable engine rather than a single proprietary game.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Who maintains Luanti?$q$, $q$Luanti is maintained by a volunteer community known as the Luanti Team, with development conducted openly on GitHub under the luanti-org organization.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Custom voxel game development$q$, $q$Developers use Luanti's Lua API to build entirely original voxel games distinct from the bundled Minetest game.$q$, $q$Hobbyist and indie game developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Educational programming projects$q$, $q$Educators use Luanti's moddable, free engine to teach Lua scripting and game logic concepts in classroom settings.$q$, $q$Educators and students$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Free community sandbox play$q$, $q$Players run or join community servers for cooperative building and survival gameplay without licensing costs.$q$, $q$Sandbox and open-source gaming communities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full engine and client access","Lua modding API","ContentDB mod repository access","Cross-platform builds","Multiplayer and server hosting support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Luanti is a free, open-source voxel game engine originally launched in 2010 as Minetest and renamed in October 2024. It lets anyone play, mod, or build entirely new block-based games using a Lua scripting API.$q$, $q$The project is community-maintained with no company or headquarters, distributed under the MIT license for its code and Creative Commons licenses for game content.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Luanti supports single-player, local multiplayer, and dedicated server play across a massive voxel world, with a Lua API that exposes nearly every part of the engine for custom games and mods.$q$, $q$The ContentDB repository hosts thousands of community mods, games, and texture packs, and the engine runs natively on Windows, macOS, Linux, BSD, and Android.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Luanti is entirely free to download, use, modify, and redistribute under its open-source license, with no paid tiers, subscriptions, or in-app purchases from the core project.$q$, $q$Community-run servers and some third-party content may carry their own separate costs, but the official engine and client remain free.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('77a26385-9077-48ad-bcca-92dcc22cef2e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Service record tracking$q$, $q$Log detailed maintenance and repair history per vehicle, with the ability to attach receipts and documents.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Fuel economy tracking$q$, $q$Records fuel entries and calculates mileage in MPG, UK MPG, L/100KM, or KM/L.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Maintenance reminders$q$, $q$Set reminders based on either a calendar date or an odometer mileage threshold.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Expense dashboard$q$, $q$Summarizes vehicle-related spending by year, month, and category.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Multi-user and SSO support$q$, $q$Supports multiple accounts on one instance plus single sign-on for centralized authentication.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$CSV import/export and API$q$, $q$Move data in or out of the app via CSV files or integrate with other tools through a documented API.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Supplies tracking$q$, $q$Tracks consumable inventory like oil, filters, or parts tied to specific vehicles.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Professional vehicle reports$q$, $q$Generates polished service history reports useful for vehicle resale or documentation.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Completely free and open source with no subscription cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Full data ownership through self-hosting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Detailed maintenance, fuel, and supplies tracking in one app$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Active development with frequent GitHub releases$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Docker-based deployment makes setup straightforward for self-hosters$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Requires self-hosting technical know-how such as Docker or a home server$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$No official cloud-hosted version for non-technical users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$No dedicated mobile app, relies on the web interface$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Support is community-driven rather than a commercial help desk$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Smaller ecosystem and brand recognition than mainstream consumer car apps$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Is LubeLogger free?$q$, $q$Yes, LubeLogger is completely free and open source under the MIT license, with no subscription fees or paywalled features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Do I need to self-host LubeLogger?$q$, $q$Yes, LubeLogger is a self-hosted application distributed as a Docker container or Windows executable, so users deploy it on their own server or device.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Can multiple people use one LubeLogger instance?$q$, $q$Yes, LubeLogger supports multiple user accounts on a single instance, including single sign-on for centralized authentication.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Can I try LubeLogger before installing it?$q$, $q$Yes, a public demo instance is available at demo.lubelogger.com to test the interface before self-hosting.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$What units does LubeLogger support for fuel tracking?$q$, $q$LubeLogger supports MPG, UK MPG, liters per 100 kilometers, and kilometers per liter for fuel economy calculations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Who develops LubeLogger?$q$, $q$LubeLogger is developed by Hargata Softworks, based in Price, Utah, and is published as open source on GitHub under the hargata/lubelog repository.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Personal vehicle maintenance tracking$q$, $q$Individual car owners log service history, fuel economy, and maintenance reminders for one or more personal vehicles.$q$, $q$Individual vehicle owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Self-hosted home-lab deployment$q$, $q$Home-lab and self-hosting enthusiasts run LubeLogger alongside other self-hosted apps on a home server or NAS.$q$, $q$Self-hosting and home-lab enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Small fleet or household multi-vehicle tracking$q$, $q$Households or small operators with several vehicles use multi-user support to track maintenance across a small fleet.$q$, $q$Small fleet operators and multi-vehicle households$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full application access","Docker and Windows executable distribution","Multi-user support","API access","CSV import/export"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LubeLogger is a free, open-source, self-hosted application for tracking vehicle service history, maintenance planning, and fuel economy. It is developed by Hargata Softworks and distributed primarily as a Docker container.$q$, $q$Because it is self-hosted, all vehicle and maintenance data stays on infrastructure the user controls, distinguishing it from cloud-based consumer car maintenance apps.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The app includes an expense dashboard, a maintenance planner, detailed service record logging with document attachments, multi-unit fuel economy tracking, date- or mileage-based reminders, and a supplies tracker.$q$, $q$It also supports multiple user accounts, customizable fields, CSV import and export, an API, single sign-on, and professional vehicle report generation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$LubeLogger is completely free and open source under the MIT license, with no subscription fees, feature paywalls, or advertising.$q$, $q$Users only incur the cost of the infrastructure they choose to self-host it on, such as a home server or a low-cost VPS.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('270d9194-a92c-41d2-84b2-40be25395e12', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Dynamic heatmaps$q$, $q$Visualizes where visitors click, how far they scroll, and where they move their mouse on any page.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Session recordings$q$, $q$Replays individual visitor sessions to see exactly how users navigate and interact with a site.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Conversion funnels$q$, $q$Tracks multi-step processes like checkout to identify where visitors abandon.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Form analytics$q$, $q$Identifies which specific form fields cause hesitation or abandonment.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Discovery AI$q$, $q$An AI layer that automatically surfaces behavioral patterns and friction points from recordings and heatmaps.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Live chat and live visitor view$q$, $q$Lets teams message visitors currently browsing the site and watch their activity in real time.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Surveys and announcements$q$, $q$Collects on-site visitor feedback or broadcasts messages directly on pages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Unlimited team members$q$, $q$All plans allow unlimited team seats regardless of pricing tier.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Every plan includes the full feature set, including Discovery AI, with no feature gating$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Native Shopify and BigCommerce app integrations for e-commerce teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Bootstrapped company with a long, stable operating history since 2010$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Straightforward session-based pricing that is easy to forecast$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$7-day free trial with no credit card required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Pricing scales quickly for high-traffic sites once past entry tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Base data retention of 60 days requires a paid upgrade for longer history$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Competes against free tools like Microsoft Clarity on core heatmap and recording features$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Additional websites cost extra per site$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Less enterprise-focused depth than dedicated tools like FullStory for very large organizations$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$How much does Lucky Orange cost?$q$, $q$Plans start at 32 dollars per month for up to 3,500 monthly sessions when billed annually, scaling up to custom Enterprise pricing for sites with 700,000 or more sessions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Does Lucky Orange offer a free trial?$q$, $q$Yes, Lucky Orange offers a 7-day free trial across its plans with no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$What is Discovery AI in Lucky Orange?$q$, $q$Discovery AI is Lucky Orange's AI feature that automatically surfaces behavioral patterns and friction points from session recordings and heatmap data.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Is Lucky Orange available for Shopify?$q$, $q$Yes, Lucky Orange has a native Shopify app as well as a BigCommerce integration for e-commerce heatmaps and session recordings.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Are all features included on every Lucky Orange plan?$q$, $q$Yes, every paid plan includes the same full feature set, heatmaps, recordings, surveys, live chat, and Discovery AI, differing only by tracked monthly session volume.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$How long does Lucky Orange store visitor data?$q$, $q$Base plans include 60 days of data retention, with paid upgrades available to extend retention to 90, 180, or 365 days.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$E-commerce conversion optimization$q$, $q$Shopify and BigCommerce store owners use heatmaps and funnels to find checkout friction and abandoned cart causes.$q$, $q$E-commerce store owners and CRO teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$SaaS onboarding analysis$q$, $q$Product and marketing teams use session recordings and form analytics to improve signup and onboarding flows.$q$, $q$SaaS marketing and product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Real-time visitor engagement$q$, $q$Support teams use live chat and live visitor view to proactively engage visitors currently browsing the site.$q$, $q$Sales and customer support teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Build$q$, $q$$32/month$q$, $q$Billed annually$q$, NULL, $q$["Up to 3,500 monthly sessions","Full feature set including Discovery AI","60-day data retention"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Grow$q$, $q$$72/month$q$, $q$Billed annually$q$, NULL, $q$["Up to 10,000 monthly sessions","Full feature set including Discovery AI","Most popular plan"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Expand$q$, $q$$199/month$q$, $q$Billed annually$q$, NULL, $q$["Starts at 50,000 monthly sessions","Full feature set including Discovery AI"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Scale$q$, $q$$839/month$q$, $q$Billed annually$q$, NULL, $q$["Starts at 300,000 monthly sessions","Full feature set including Discovery AI"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["700,000+ monthly sessions","Dedicated support","Custom data retention and site limits"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lucky Orange is a conversion rate optimization suite offering heatmaps, session recordings, funnels, surveys, live chat, and AI-driven behavioral insights. Founded in 2010 and based in Overland Park, Kansas, it serves over 500,000 websites.$q$, $q$The company has positioned itself as a bootstrapped, self-funded business rather than a venture-backed startup, which shapes its all-features-included pricing approach.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform tracks visitor clicks, scrolling, and mouse movement to generate dynamic heatmaps, and records individual visitor sessions for replay, alongside form analytics that isolate friction-causing fields.$q$, $q$Conversion funnels visualize multi-step drop-off, Discovery AI surfaces patterns automatically, and live chat with live visitor view lets teams engage visitors in real time.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('33ec13b1-2e9a-4373-9b50-55b018d5adaa', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pricing scales by monthly tracked sessions rather than by feature tier, so every plan from Build through Scale includes the full feature set including Discovery AI.$q$, $q$Plans start at 32 dollars per month for 3,500 sessions and scale to custom Enterprise pricing for sites exceeding 700,000 monthly sessions, with a 7-day free trial available.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Dream Machine video generation$q$, $q$Text-to-video, image-to-video, video-to-video, and video extension generation through a consumer web app.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Ray3 reasoning video model$q$, $q$Luma's advanced video model capable of generating high-fidelity 16-bit HDR video output.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Photon image generation$q$, $q$Fast, high-quality text-to-image and image generation models, including a lower-cost Flash variant.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Genie text-to-3D$q$, $q$Generates downloadable 3D mesh assets in GLB, OBJ, or USDZ format in roughly ten seconds.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Developer API$q$, $q$Programmatic access to Dream Machine, Photon, Ray, and Genie models for integration into external products.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Agent tooling$q$, $q$Automated Luma Agents with usage tiers that scale across Plus, Pro, and Ultra subscription plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Team collaboration$q$, $q$Shared projects, team organization, and credit pooling on Team and Enterprise plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Enterprise fine-tuning$q$, $q$Custom model fine-tuning and enterprise commitments available on the Enterprise plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Strong reasoning-capable video model with high-fidelity HDR output via Ray3$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Broad product suite spanning video, image, and 3D generation$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Well-funded with over 1 billion dollars raised, supporting rapid model development$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Usage-based API pricing allows flexible integration for developers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Genie offers fast, practical 3D asset generation for games and prototyping$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Credit-based consumer pricing can be difficult to estimate for heavy users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Business and Enterprise pricing is not publicly disclosed$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Faces intense competition from well-funded rivals like OpenAI Sora, Google Veo, and Runway$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Frequent name confusion with unrelated companies Lu.ma and Luma Health$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Rapid model iteration can make older outputs and workflows quickly outdated$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Is Luma AI the same company as Lu.ma?$q$, $q$No, they are completely unrelated companies. Luma AI at lumalabs.ai builds generative AI video, image, and 3D tools, while Lu.ma is a separate events and ticketing platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$What is Dream Machine?$q$, $q$Dream Machine is Luma AI's text-to-video and image-to-video web application, launched in June 2024, that lets users generate video clips from prompts, images, or existing footage.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$How much does Luma AI cost?$q$, $q$Consumer plans start around 25 to 30 dollars per month for the Plus tier, scaling to roughly 300 dollars per month for Ultra, with custom pricing for Team and Enterprise plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$What is Genie in Luma AI?$q$, $q$Genie is Luma AI's text-to-3D tool that generates downloadable 3D mesh files in formats like GLB, OBJ, and USDZ in about ten seconds.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$How much funding has Luma AI raised?$q$, $q$Luma AI has raised over 1.07 billion dollars, including a 900 million dollar Series C in November 2025 led by Saudi Arabia's HUMAIN at a valuation above 4 billion dollars.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Does Luma AI offer an API?$q$, $q$Yes, Luma AI launched a developer API in September 2024 covering its Dream Machine video, Photon image, and Genie 3D models with usage-based pricing.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Short-form AI video content creation$q$, $q$Creators and marketers use Dream Machine to generate short video clips from text prompts or existing images for social content.$q$, $q$Content creators and marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Rapid 3D asset prototyping$q$, $q$Game developers and 3D artists use Genie to quickly generate downloadable 3D meshes for prototyping without manual modeling.$q$, $q$Game developers and 3D artists$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$API-integrated generative media pipelines$q$, $q$Developers and enterprises integrate Luma's video, image, and 3D models into their own applications via the developer API.$q$, $q$Developers and enterprise product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Plus$q$, $q$$30/month ($25/month annual)$q$, $q$Monthly or annual$q$, NULL, $q$["10,000 credits","Access to Luma and third-party models","Guest collaborator edit access","Commercial use permitted"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Pro$q$, $q$$90/month ($75/month annual)$q$, $q$Monthly or annual$q$, NULL, $q$["40,000 credits","4x usage with Luma Agents","Everything in Plus"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Ultra$q$, $q$$300/month ($250/month annual)$q$, $q$Monthly or annual$q$, NULL, $q$["150,000 credits","15x usage with Luma Agents","Everything in Pro"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Team$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Team member management","Shared credits and usage analytics","SSO authentication"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Everything in Team","Enterprise commitments","Custom fine-tuning","Educational support and training"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Luma AI is a generative AI company founded in 2021 and based in Palo Alto, California, best known for Dream Machine, its text-to-video and image-to-video web application launched in June 2024.$q$, $q$It is a completely separate company from Lu.ma, the events and ticketing platform, and Luma Health, the healthcare patient engagement company, despite the shared Luma name.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The product suite includes Dream Machine for video generation, the Ray2 and Ray3 reasoning video models, Photon and Photon Flash for fast image generation, and Genie for text-to-3D mesh generation.$q$, $q$Models are accessible through both consumer web apps and a developer API launched in September 2024, with usage-based pricing for API access.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35ea48fd-76db-4106-94b4-24dc1d80bfc9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Consumer plans include Plus, Pro, and Ultra subscription tiers priced from roughly 25 to 300 dollars per month depending on billing cycle, each with escalating monthly credit allowances.$q$, $q$Team and Enterprise plans are custom-priced and add SSO, shared credits, and fine-tuning, while API usage is billed per generation.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$EHR integration$q$, $q$Connects with major electronic health record and practice management systems to sync scheduling and patient data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Automated appointment reminders$q$, $q$Sends multi-channel reminders via text, email, and phone to reduce patient no-shows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Digital intake forms$q$, $q$Lets patients complete registration and intake paperwork digitally before their visit.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Waitlist backfill automation$q$, $q$Automatically offers open appointment times to waitlisted patients when cancellations occur.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Referral scheduling$q$, $q$Coordinates and schedules patient referrals between providers within a health system.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Patient recall campaigns$q$, $q$Automates follow-up outreach for preventive care and post-visit recall.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Multi-channel communication$q$, $q$Supports text messaging, email, and phone as unified communication channels with patients.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Operational AI workflows$q$, $q$AI-assisted automation for scheduling, outreach, and administrative decision-making across the patient journey.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Deep integration with a wide range of existing EHR systems$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Automates high-volume administrative tasks like reminders and waitlist management$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Well-suited to complex, multi-location health systems$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Backed by significant funding, including a 130 million dollar Series C$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Reduces no-show rates and front-office administrative burden$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Pricing is not public and requires a sales consultation to obtain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Best suited to larger health systems rather than small independent practices$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Implementation complexity tied to EHR integration can extend rollout timelines$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Reported per-user costs may be high for smaller organizations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Competes in a crowded patient engagement software market$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Is Luma Health the same as Lu.ma or Luma AI?$q$, $q$No, Luma Health is a separate healthcare patient engagement company unrelated to Lu.ma, the events platform, or Luma AI, the generative video company.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$How much does Luma Health cost?$q$, $q$Luma Health uses custom, quote-based pricing based on organization size and needs; it does not publish pricing publicly, though some reviews estimate costs around 250 dollars per user per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$What does Luma Health do?$q$, $q$Luma Health automates patient engagement tasks such as appointment reminders, digital intake, waitlist backfill, referral scheduling, and follow-up recall for healthcare organizations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Does Luma Health integrate with EHR systems?$q$, $q$Yes, Luma Health is built to integrate with a wide range of existing electronic health record and practice management systems.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Who uses Luma Health?$q$, $q$Luma Health is primarily used by hospital systems, multi-specialty clinics, and other larger healthcare provider organizations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$When was Luma Health founded?$q$, $q$Luma Health was founded in 2015 and is headquartered in San Mateo, California.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Reducing patient no-shows$q$, $q$Health systems use automated multi-channel reminders and waitlist backfill to reduce missed appointments and fill cancellations quickly.$q$, $q$Hospital and clinic scheduling teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Streamlining referral coordination$q$, $q$Multi-specialty systems use Luma Health to automate scheduling of patient referrals between providers.$q$, $q$Health system care coordination teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Automating preventive care outreach$q$, $q$Organizations use recall campaigns to automatically follow up with patients due for preventive or follow-up care.$q$, $q$Population health and patient outreach teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$Custom$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["EHR integration","Automated reminders and intake","Waitlist backfill","Referral scheduling","Recall campaigns"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Luma Health is a healthcare patient engagement and scheduling platform founded in 2015 and headquartered in San Mateo, California, used by hospitals and clinics to automate patient communication and care coordination.$q$, $q$It is unrelated to Lu.ma, the events platform, and Luma AI, the generative video company, despite sharing the Luma name.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform integrates with electronic health record systems to automate appointment reminders, digital intake, waitlist backfill, referral scheduling, and post-visit follow-up across text, email, and phone channels.$q$, $q$Luma Health has increasingly positioned its product around operational AI, aiming to automate scheduling and outreach decisions rather than simply sending reminders.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6bc44bb-56fc-4d52-8fe2-1b741120a0df', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Luma Health does not publish pricing publicly and instead quotes each healthcare organization individually based on size, patient volume, feature needs, and EHR integration complexity.$q$, $q$Third-party estimates suggest costs can run around 250 dollars per user per month, though actual enterprise contract pricing varies significantly by organization.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Enterprise-scale crawling$q$, $q$Crawls very large websites with millions of URLs and surfaces over 350 technical SEO reports.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Multi-site monitoring$q$, $q$Tracks technical SEO health across multiple sites over time with trend lines and automated alerts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$CI/CD SEO testing$q$, $q$Integrates into development pipelines to catch SEO regressions in staging builds before they go live.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Executive dashboards$q$, $q$High-level reporting and benchmarking designed for non-technical executive stakeholders.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Indexability and crawl budget analysis$q$, $q$Identifies crawl budget waste, indexability issues, and site architecture problems at scale.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Duplicate content detection$q$, $q$Surfaces duplicate content and canonicalization issues across large site sections.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$AI search readiness reporting$q$, $q$Reporting extended to cover GEO and AEO, AI-driven search and answer engine visibility.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Custom integrations$q$, $q$Connects into enterprise workflows and CI/CD systems for automated, ongoing SEO governance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Purpose-built for very large, complex enterprise websites$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Protect module catches SEO issues before deployment, not just after$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Long operating history and enterprise client base since 2010$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Coordinated four-module suite spans crawling, monitoring, and executive reporting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Trusted by major brands including Adobe, Microsoft, and PayPal$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Pricing is not publicly disclosed, requiring a sales consultation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Positioned for enterprise budgets, likely too costly for small businesses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Reported employee counts vary widely across sources, suggesting limited public transparency$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Learning curve for teams new to large-scale technical SEO crawling$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Less suited to quick, ad hoc audits than lighter tools like Screaming Frog$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Is Lumar the same as DeepCrawl?$q$, $q$Yes, Lumar is the rebranded name for DeepCrawl, which changed its name on September 29, 2022, while continuing the same core crawling technology and team.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$How much does Lumar cost?$q$, $q$Lumar uses custom, quote-based pricing tailored to a customer's chosen modules, crawl volume, and number of sites, and does not publish pricing publicly.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$What modules does Lumar offer?$q$, $q$Lumar's platform includes Analyze for crawling, Monitor for ongoing multi-site tracking, Protect for CI/CD SEO testing, and Impact for executive dashboards.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Who uses Lumar?$q$, $q$Lumar is used by enterprise organizations with large, complex websites, including reported clients such as Adobe, Microsoft, eBay, PayPal, Comcast, and Deloitte.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Where is Lumar headquartered?$q$, $q$Lumar is headquartered in London, United Kingdom, with additional offices reported in New York and Krakow, Poland.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$What is Lumar's Protect feature?$q$, $q$Protect integrates into a customer's CI/CD pipeline to test staging builds for SEO regressions and stop harmful changes before they reach production.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Large-scale technical SEO audits$q$, $q$Enterprise SEO teams crawl millions of URLs to identify indexability, duplicate content, and crawl budget issues.$q$, $q$Enterprise technical SEO teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Pre-deployment SEO regression testing$q$, $q$Engineering and SEO teams use Protect to catch SEO-breaking changes in staging before they reach production.$q$, $q$Web engineering and DevOps teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Executive SEO health reporting$q$, $q$Marketing leadership uses Impact dashboards to track overall site health and business impact without digging into raw crawl data.$q$, $q$Marketing executives and stakeholders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$Custom$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Analyze crawler module","Monitor tracking module","Protect CI/CD testing module","Impact executive dashboards"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lumar is an enterprise technical SEO and website intelligence platform, founded in 2010 as DeepCrawl and rebranded to Lumar in September 2022. It is built for large organizations managing complex, high-URL-volume websites.$q$, $q$The platform is organized into four modules, Analyze, Monitor, Protect, and Impact, spanning crawling, ongoing monitoring, pre-deploy SEO testing, and executive-level reporting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Analyze crawls large sites and generates over 350 technical SEO reports, while Monitor tracks multiple sites over time with trend lines and alerts for regressions.$q$, $q$Protect hooks into CI/CD pipelines to catch SEO issues in staging before deployment, and Impact provides executive dashboards summarizing site health and business impact.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76b116d0-5bc2-4a6a-93eb-906109fc7d61', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lumar does not publish pricing publicly and instead offers custom, quote-based packages tailored to a customer's chosen modules, crawl volume, and number of sites.$q$, $q$Prospective customers must submit a request through Lumar's sales team to receive pricing, which is typical of enterprise-tier SEO and website intelligence platforms.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Native cross-platform desktop app$q$, $q$Runs natively on Windows, macOS, and Linux, and works fully offline without requiring a browser.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Sketch file compatibility$q$, $q$Opens, edits, and saves native .sketch files, enabling collaboration with Sketch users on non-Mac systems.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Built-in AI tools$q$, $q$Includes an AI background remover, image upscaler, and avatar generator directly inside the editor.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Integrated asset library$q$, $q$Direct in-app access to over 1.5 million free icons, photos, illustrations, and mockups from Icons8.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Interactive prototyping$q$, $q$Lets designers create clickable prototypes by linking artboards together.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Responsive design constraints$q$, $q$Supports layout rules and constraints so designs adapt across different screen sizes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Cloud collaboration (paid)$q$, $q$Optional cloud document storage, team sharing, and version history on paid subscription tiers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Vector editing toolkit$q$, $q$Full vector drawing, editing, and artboard tools comparable to standard UI design software.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Core design editor is free for personal and commercial use with no major feature gating$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Native desktop apps for Windows, macOS, and Linux with full offline support$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Built-in access to a massive free icon, photo, and illustration library$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Includes AI tools like background removal and upscaling at no extra base cost$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Native .sketch file compatibility helps teams collaborate across platforms$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Smaller collaborative and plugin ecosystem than Figma$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Cloud collaboration and full asset library access require paid add-ons$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Backed by a much smaller company than venture-funded competitors like Figma$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Less brand recognition and community content compared to Figma or Sketch$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Real-time multiplayer collaboration is less mature than browser-first competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Is Lunacy really free?$q$, $q$Yes, the core Lunacy desktop editor is free for both personal and commercial use with no major feature restrictions; paid add-ons only cover cloud storage, larger teams, and the full asset and AI library.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Who makes Lunacy?$q$, $q$Lunacy is developed by Icons8, a design-assets company that also provides the icon, photo, and illustration library integrated directly into the app.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Does Lunacy work offline?$q$, $q$Yes, unlike browser-based tools such as Figma, Lunacy runs as a native desktop application on Windows, macOS, and Linux and works fully offline.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Can Lunacy open Sketch files?$q$, $q$Yes, Lunacy natively opens, edits, and saves .sketch files, which was its original purpose when it launched as a Sketch file viewer in 2016.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$What AI tools does Lunacy include?$q$, $q$Lunacy includes an AI background remover, an image upscaler, and an AI avatar generator built directly into the editor.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$How does Lunacy compare to Figma?$q$, $q$Lunacy is a free, native desktop alternative to Figma with offline support and a bundled asset library, though it has a smaller plugin ecosystem and less mature real-time collaboration than Figma.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Free UI and product design$q$, $q$Designers use Lunacy to create app and website interfaces with vector tools and prototyping at no cost.$q$, $q$Solo designers and startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Cross-platform Sketch file collaboration$q$, $q$Windows and Linux users open and edit .sketch files created by Mac-based team members using Sketch.$q$, $q$Mixed-OS design teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Offline design work$q$, $q$Designers who need to work without an internet connection use Lunacy's native desktop app instead of browser-based tools.$q$, $q$Freelancers and remote designers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Full core design editor","Up to 3 team members","10 cloud documents","Basic asset access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Personal Cloud$q$, $q$$4.99/month ($47.99/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited private cloud documents","Extended file version history","Extended file recovery window"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Professional Team$q$, $q$$4.99/seat/month$q$, $q$Monthly$q$, NULL, $q$["No limits on documents","No limits on file versions","No limits on deleted file storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$Assets and AI Subscription$q$, $q$$9.99/month ($95.99/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited Icons8 asset downloads without attribution","Full access to AI design tools"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lunacy is a free, cross-platform graphic and UI design tool made by Icons8. It began in 2016 as a Windows viewer for Sketch files and evolved into a full vector design editor running natively on Windows, macOS, and Linux.$q$, $q$It is positioned as a free alternative to Figma and Sketch, with the added advantage of full offline functionality since it runs as a native desktop application rather than requiring a browser connection.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Lunacy supports artboards, responsive design constraints, interactive prototyping, and native .sketch file compatibility, and it ships with built-in AI tools such as background removal, image upscaling, and avatar generation.$q$, $q$The app includes direct in-canvas access to Icons8's library of over 1.5 million free icons, photos, and illustrations, reducing the need for separate stock asset subscriptions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d2f9ed7-498a-4028-a5a4-cc3e13c64bcc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Lunacy desktop editor is free for personal and commercial use with no major feature restrictions, distinguishing it from most competitors that gate core functionality behind paywalls.$q$, $q$Paid add-ons cover cloud storage and collaboration, priced from about 4.99 dollars per month, and a separate asset and AI subscription costs roughly 9.99 dollars per month.$q$]::text[], 2);
